import React from 'react';

const ProductList = ({ products, onEdit, onDelete }) => {
    return (
        <div>
            {products.length > 0 ? (
                products.map((product) => (
                    <div key={product.codigo} style={{ margin: '10px', border: '1px solid #ccc', padding: '10px' }}>
                        <h3>Nome: {product.nome}</h3>
                        <p>Descrição: {product.descricao}</p>
                        <p>Código: {product.codigo}</p>
                        <p>Categoria: {product.categoria}</p>
                        <p>Preço: R$ {parseFloat(product.preco).toFixed(2)}</p>
                        <p>Quantidade Mínima: {product.quantidade_minima}</p>
                        <button onClick={() => onEdit(product)}>Editar</button>
                        <button onClick={() => onDelete(product.codigo)}>Excluir</button>
                    </div>
                ))
            ) : (
                <p>Nenhum produto encontrado.</p>
            )}
        </div>
    );
};

export default ProductList;
